# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management']
users = db['users']

@app.route('/user', methods=['POST'])
def create_user():
    data = request.get_json()
    user_id = users.insert_one(data).inserted_id
    return jsonify({'id': str(user_id)}), 201

@app.route('/user/<user_id>', methods=['GET'])
def get_user(user_id):
    user = users.find_one({'_id': user_id})
    if user:
        return jsonify(user)
    else:
        return jsonify({'message': 'User not found'}), 404

@app.route('/document/query', methods=['POST'])
def query_documents():
    data = request.get_json()
    results = list(users.find(data))
    return jsonify(results)

@app.route('/document/aggregation', methods=['POST'])
def aggregate_documents():
    pipeline = request.get_json()
    results = list(users.aggregate(pipeline))
    return jsonify(results)

if __name__ == '__main__':
    app.run(debug=True)